import{_ as a,p as e,q as h,a1 as r}from"./framework-e0dd9823.js";const d={},i=r('<h1 id="第-4-单元总结" tabindex="-1"><a class="header-anchor" href="#第-4-单元总结" aria-hidden="true">#</a> 第 4 单元总结</h1><h2 id="欲しい-愿望" tabindex="-1"><a class="header-anchor" href="#欲しい-愿望" aria-hidden="true">#</a> 欲しい（愿望）</h2><p>今、何がいちばん欲しいですか。 洋服がいちばん欲しいです。 何も欲しいくないです。</p><h2 id="たい-意愿的助动词" tabindex="-1"><a class="header-anchor" href="#たい-意愿的助动词" aria-hidden="true">#</a> たい（意愿的助动词）</h2><p>日曜日、何をしたいですか。 わたしは映画を見たいです。 何もしたくないです。</p><h2 id="ませんか-建议" tabindex="-1"><a class="header-anchor" href="#ませんか-建议" aria-hidden="true">#</a> ませんか（建议）</h2><p>一緒にお茶を飲みませんか。</p><h2 id="ましょう-提议" tabindex="-1"><a class="header-anchor" href="#ましょう-提议" aria-hidden="true">#</a> ましょう（提议）</h2><p>ちょっと、休みましょう</p><h2 id="でも-无论···都···" tabindex="-1"><a class="header-anchor" href="#でも-无论···都···" aria-hidden="true">#</a> でも（无论···都···）</h2><p>だれでもわかります。 いつでも電話をしてください。 何でもいいです。</p><h2 id="形容词-名词连接动词-副词用法" tabindex="-1"><a class="header-anchor" href="#形容词-名词连接动词-副词用法" aria-hidden="true">#</a> 形容词，名词连接动词（副词用法）</h2><p>形 1：去掉词尾“い”后加“く”，例如“小さい” → “小さくなりました”； 形 2：直接在词尾加“に”，例如“きれい” → “きれいになります”； 名词：直接在词尾加“に”，例如“医者”　 → “医者になります”；</p><h2 id="なります-します-变化" tabindex="-1"><a class="header-anchor" href="#なります-します-变化" aria-hidden="true">#</a> なります/します（变化）</h2>',14),n=[i];function t(c,s){return e(),h("div",null,n)}const l=a(d,[["render",t],["__file","unit20-2.html.vue"]]);export{l as default};
